import { useEffect, useRef } from 'react';
import { NavigationContainer } from '@react-navigation/native';
import * as Notifications from 'expo-notifications';
import { useNavigation } from '@react-navigation/native';

// Configuration du handler d'affichage des notifications en premier plan
Notifications.setNotificationHandler({
  handleNotification: async (notification) => ({
    shouldShowAlert: true,
    shouldPlaySound: true,
    shouldSetBadge: true,
  }),
});

function App() {
  const navigationRef = useRef();
  const responseListener = useRef();
  const notificationListener = useRef();

  // Gérer la navigation vers le détail de la commande
  const navigateToOrder = (orderId) => {
    if (navigationRef.current) {
      navigationRef.current.navigate('OrderDetails', { orderId });
    }
  };

  useEffect(() => {
    // Écouter les notifications reçues en premier plan
    notificationListener.current = Notifications.addNotificationReceivedListener(
      (notification) => {
        console.log('Notification reçue:', notification);
        // Optionnel : afficher un toast ou mettre à jour l'UI
      }
    );

    // Écouter la réponse de l'utilisateur à une notification
    responseListener.current = Notifications.addNotificationResponseReceivedListener(
      (response) => {
        const orderId = response.notification.request.content.data.orderId;
        if (orderId) {
          navigateToOrder(orderId);
        }
      }
    );

    // Gérer les notifications qui ont ouvert l'application
    const checkInitialNotification = async () => {
      const response = await Notifications.getLastNotificationResponseAsync();
      if (response && response.notification.request.content.data.orderId) {
        navigateToOrder(response.notification.request.content.data.orderId);
      }
    };

    checkInitialNotification();

    return () => {
      if (notificationListener.current) {
        Notifications.removeNotificationSubscription(notificationListener.current);
      }
      if (responseListener.current) {
        Notifications.removeNotificationSubscription(responseListener.current);
      }
    };
  }, []);

  // Fonction pour envoyer une notification locale (exemple)
  const sendLocalStatusNotification = async (orderId, status) => {
    const statusMessages = {
      confirmed: '✅ Votre commande a été confirmée !',
      shipped: '📦 Votre commande a été expédiée !',
      delivered: '🏠 Votre commande a été livrée !',
    };

    await Notifications.scheduleNotificationAsync({
      content: {
        title: 'Mise à jour commande',
        body: statusMessages[status] || `Statut mis à jour : ${status}`,
        data: { orderId, status, screen: 'OrderDetails' },
        channelId: 'order-updates',
      },
      trigger: null, // immédiat
    });
  };

  return (
    <NavigationContainer ref={navigationRef}>
      {/* Le reste de l'application */}
    </NavigationContainer>
  );
}

export default App;
