import * as Notifications from 'expo-notifications';
import * as Device from 'expo-device';
import Constants from 'expo-constants';
import { Platform } from 'react-native';

// Obtenir le token push Expo
const getExpoPushToken = async () => {
  if (!Device.isDevice) {
    alert('Les notifications push ne fonctionnent que sur un appareil physique');
    return null;
  }

  try {
    const { status: existingStatus } = await Notifications.getPermissionsAsync();
    let finalStatus = existingStatus;

    if (existingStatus !== 'granted') {
      const { status } = await Notifications.requestPermissionsAsync();
      finalStatus = status;
    }

    if (finalStatus !== 'granted') {
      alert('Permissions de notification refusées');
      return null;
    }

    const projectId = Constants.expoConfig?.extra?.eas?.projectId ?? Constants.expoConfig?.projectId;

    if (!projectId) {
      console.warn('Project ID manquant pour les notifications');
      return null;
    }

    const token = await Notifications.getExpoPushTokenAsync({
      projectId: projectId,
    });

    console.log('Expo Push Token:', token.data);
    return token.data;
  } catch (error) {
    console.error('Erreur lors de la récupération du token:', error);
    return null;
  }
};

// Enregistrer le token sur le backend
const registerPushToken = async (token, userId) => {
  try {
    const response = await fetch('https://api.example.com/users/push-token', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${await getAuthToken()}`,
      },
      body: JSON.stringify({
        userId,
        pushToken: token,
        platform: Platform.OS,
        deviceName: Device.deviceName,
      }),
    });

    if (!response.ok) {
      throw new Error('Erreur lors de l\'enregistrement du token');
    }

    return true;
  } catch (error) {
    console.error('Erreur:', error);
    return false;
  }
};

// Supprimer le token du backend (déconnexion)
const unregisterPushToken = async (token, userId) => {
  try {
    const response = await fetch('https://api.example.com/users/push-token', {
      method: 'DELETE',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${await getAuthToken()}`,
      },
      body: JSON.stringify({ userId, pushToken: token }),
    });

    return response.ok;
  } catch (error) {
    console.error('Erreur lors de la suppression du token:', error);
    return false;
  }
};

// Hook personnalisé pour gérer le token push
const usePushNotifications = (isAuthenticated, userId) => {
  useEffect(() => {
    let token = null;

    const setupPushNotifications = async () => {
      if (!isAuthenticated) return;

      token = await getExpoPushToken();
      if (token) {
        await registerPushToken(token, userId);
      }
    };

    setupPushNotifications();

    return () => {
      if (token && isAuthenticated) {
        unregisterPushToken(token, userId);
      }
    };
  }, [isAuthenticated, userId]);
};
