import * as Notifications from 'expo-notifications';
import AsyncStorage from '@react-native-async-storage/async-storage';

const REMINDER_SCHEDULED_KEY = '@cart_reminder_scheduled';

const scheduleCartReminder = async (cartItems) => {
  if (!cartItems || cartItems.length === 0) {
    // Annuler le rappel si le panier est vide
    await cancelCartReminder();
    return;
  }

  // Vérifier si un rappel est déjà planifié
  const alreadyScheduled = await AsyncStorage.getItem(REMINDER_SCHEDULED_KEY);
  if (alreadyScheduled === 'true') {
    console.log('Rappel déjà planifié');
    return;
  }

  const itemCount = cartItems.reduce((sum, item) => sum + item.quantity, 0);
  const total = cartItems.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  // Planifier la notification dans 30 minutes
  const trigger = new Date(Date.now() + 30 * 60 * 1000);

  const notificationId = await Notifications.scheduleNotificationAsync({
    content: {
      title: '🛒 Vous avez oublié quelque chose ?',
      body: `Votre panier contient ${itemCount} article(s) pour un total de ${total.toFixed(2)} €. Terminez votre commande !`,
      data: { screen: 'Cart' },
      channelId: 'reminders',
      categoryIdentifier: 'cart-reminder',
    },
    trigger,
  });

  // Sauvegarder l'ID de la notification planifiée
  await AsyncStorage.setItem(REMINDER_SCHEDULED_KEY, 'true');
  await AsyncStorage.setItem('@cart_reminder_id', notificationId);

  console.log('Rappel planifié pour dans 30 minutes');
};

const cancelCartReminder = async () => {
  const notificationId = await AsyncStorage.getItem('@cart_reminder_id');
  if (notificationId) {
    await Notifications.cancelScheduledNotificationAsync(notificationId);
    await AsyncStorage.removeItem(REMINDER_SCHEDULED_KEY);
    await AsyncStorage.removeItem('@cart_reminder_id');
    console.log('Rappel annulé');
  }
};

// Utilisation dans le composant CartScreen
useEffect(() => {
  if (cartItems.length > 0) {
    scheduleCartReminder(cartItems);
  } else {
    cancelCartReminder();
  }

  return () => {
    // Annuler le rappel si le composant se démonte (commande finalisée)
    if (cartItems.length === 0) {
      cancelCartReminder();
    }
  };
}, [cartItems]);
