import * as Notifications from 'expo-notifications';
import { Platform } from 'react-native';

const setAppBadge = async (count) => {
  try {
    // Définir le badge
    await Notifications.setBadgeCountAsync(count);

    console.log(`Badge mis à jour : ${count}`);
  } catch (error) {
    console.error('Erreur lors de la mise à jour du badge:', error);
  }
};

// Incrémenter le badge
const incrementBadge = async () => {
  const currentBadge = await Notifications.getBadgeCountAsync();
  await setAppBadge(currentBadge + 1);
};

// Décrémenter le badge (quand l'utilisateur ouvre la notification)
const decrementBadge = async () => {
  const currentBadge = await Notifications.getBadgeCountAsync();
  if (currentBadge > 0) {
    await setAppBadge(currentBadge - 1);
  }
};

// Réinitialiser le badge (à 0)
const resetBadge = async () => {
  await setAppBadge(0);
};

// Utilisation : lorsque l'utilisateur ouvre l'application
useEffect(() => {
  resetBadge();
}, []);

// Utilisation : à la réception d'une nouvelle commande
const onNewOrderReceived = async (order) => {
  if (order.status === 'pending') {
    await incrementBadge();
    await Notifications.scheduleNotificationAsync({
      content: {
        title: 'Nouvelle commande',
        body: `Commande #${order.id} en attente de validation`,
        badge: 1,
      },
      trigger: null,
    });
  }
