import * as Notifications from 'expo-notifications';
import * as Device from 'expo-device';

class PushTokenManager {
  constructor() {
    this.currentToken = null;
    this.isRefreshing = false;
  }

  async getValidToken(forceRefresh = false) {
    if (!Device.isDevice) return null;

    // Vérifier si le token actuel est valide
    if (this.currentToken && !forceRefresh) {
      const isValid = await this.validateToken(this.currentToken);
      if (isValid) return this.currentToken;
    }

    // Rafraîchir le token
    return this.refreshToken();
  }

  async refreshToken() {
    if (this.isRefreshing) {
      // Attendre la fin du rafraîchissement en cours
      return new Promise((resolve) => {
        const checkInterval = setInterval(async () => {
          if (!this.isRefreshing) {
            clearInterval(checkInterval);
            resolve(this.currentToken);
          }
        }, 100);
      });
    }

    this.isRefreshing = true;

    try {
      // Vérifier les permissions
      const { status } = await Notifications.getPermissionsAsync();
      if (status !== 'granted') {
        console.log('Permissions non accordées');
        return null;
      }

      // Obtenir un nouveau token
      const newToken = await Notifications.getExpoPushTokenAsync({
        projectId: Constants.expoConfig?.extra?.eas?.projectId,
      });

      this.currentToken = newToken.data;

      // Envoyer le nouveau token au backend
      await this.sendTokenToBackend(this.currentToken);

      return this.currentToken;
    } catch (error) {
      console.error('Erreur lors du rafraîchissement du token:', error);
      return null;
    } finally {
      this.isRefreshing = false;
    }
  }

  async validateToken(token) {
    if (!token) return false;

    try {
      // Tester le token avec une requête ping au backend
      const response = await fetch('https://api.example.com/push-token/validate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token }),
      });

      if (response.status === 410) {
        // Token expiré (Gone)
        console.log('Token expiré, nécessite un rafraîchissement');
        return false;
      }

      return response.ok;
    } catch (error) {
      console.error('Erreur de validation du token:', error);
      return false;
    }
  }

  async sendTokenToBackend(token) {
    try {
      const response = await fetch('https://api.example.com/users/push-token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${await getAuthToken()}`,
        },
        body: JSON.stringify({ pushToken: token }),
      });

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}`);
      }

      console.log('Token enregistré avec succès');
    } catch (error) {
      console.error('Erreur d\'enregistrement:', error);
      // Planifier une nouvelle tentative
      setTimeout(() => this.sendTokenToBackend(token), 60000);
    }
  }
}

// Utilisation
export const pushTokenManager = new PushTokenManager();

// Dans le composant
useEffect(() => {
  const setupPushNotifications = async () => {
    const token = await pushTokenManager.getValidToken();
    if (token) {
      console.log('Token push valide:', token);
    }
  };

  setupPushNotifications();

  // Rafraîchir périodiquement (toutes les 24h)
  const interval = setInterval(() => {
    pushTokenManager.getValidToken(true);
  }, 24 * 60 * 60 * 1000);

  return () => clearInterval(interval);
}, []);
```
